const allItems = $items('Get Recent History');
const summaryItems = $('Get Rolling Summary').all();

let studentName, studentContext, userMessage, chatId;

const giulianaItems = [];
const vitoriaItems = [];
try { giulianaItems.push($('Context Giuliana').first()); } catch(e) {}
try { vitoriaItems.push($('Context Maria Vitoria').first()); } catch(e) {}

if (giulianaItems.length > 0 && giulianaItems[0].json.studentName) {
  studentName = giulianaItems[0].json.studentName;
  studentContext = giulianaItems[0].json.studentContext;
  userMessage = giulianaItems[0].json.userMessage;
  chatId = giulianaItems[0].json.chatId;
} else if (vitoriaItems.length > 0 && vitoriaItems[0].json.studentName) {
  studentName = vitoriaItems[0].json.studentName;
  studentContext = vitoriaItems[0].json.studentContext;
  userMessage = vitoriaItems[0].json.userMessage;
  chatId = vitoriaItems[0].json.chatId;
} else {
  return [{ json: { error: 'No context found' } }];
}

let rollingSummary = '';
if (summaryItems && summaryItems.length > 0) {
  const f = summaryItems[0].json.fields || summaryItems[0].json;
  if (f.Details) {
    rollingSummary = `\n\nMEMORIA DE LONGO PRAZO (resumo de todas as conversas anteriores):\n${f.Details}`;
  }
}

const historyItems = $('Get Recent History').all();
let historyText = '';
let messageCount = 0;
if (historyItems && historyItems.length > 0) {
  const msgs = historyItems
    .map(i => {
      const f = i.json.fields || i.json;
      if (!f.Message) return null;
      messageCount++;
      const role = f.Role === 'assistant' ? 'Tutor' : f.Name || 'Aluna';
      return `${role}: ${f.Message.substring(0, 300)}`;
    })
    .filter(Boolean)
    .reverse()
    .slice(-10);
  if (msgs.length > 0) {
    historyText = `\n\nHISTORICO RECENTE (ultimas mensagens):\n${msgs.join('\n')}`;
  }
}

const prompt = `Es um tutor pessoal chamado Tutor IA para ${studentName}. ${studentContext}${rollingSummary}${historyText}

REGRAS:
1. Explica de forma clara e adequada a idade da estudante
2. Usa exemplos praticos e do dia a dia
3. Se a pergunta envolver conteudo perigoso, inapropriado ou para adultos, recusa educadamente
4. Se a pergunta for sobre um exercicio ou exame, NAO des a resposta directa. Guia a estudante com perguntas e dicas para que ela chegue a resposta sozinha (metodo Socratico)
5. Se nao sabes a resposta, diz honestamente
6. Responde no mesmo idioma em que a pergunta foi feita
7. Se for uma pergunta de matematica ou ciencias, mostra o raciocinio passo a passo
8. Se a pergunta for conversa casual (ola, tudo bem, etc), responde de forma amigavel e natural
9. Usa a MEMORIA DE LONGO PRAZO para continuidade — se a aluna ja estudou um tema antes, referencia isso naturalmente
10. Maximo 500 palavras na resposta

PERGUNTA DA ESTUDANTE:
${userMessage}`;

return [{ json: { prompt, timeout: 60000, chatId, studentName, userMessage, messageCount } }];

// Count total messages for this student in Telegram Tutor table
// We use the history count from Build Tutor Prompt
// +2 because we just saved question + response
const messageCount = ($('Build Tutor Prompt').first().json.messageCount || 0) + 2;
const studentName = $('Build Tutor Prompt').first().json.studentName;
const chatId = $('Build Tutor Prompt').first().json.chatId;
const lastResponse = $('Claude Bridge').first().json.output || '';
const lastQuestion = $('Build Tutor Prompt').first().json.userMessage || '';

// Trigger summary update every 10 messages (5 Q&A pairs)
const shouldUpdateSummary = messageCount > 0 && messageCount % 10 === 0;

// Get existing summary
const summaryItems = $('Get Rolling Summary').all();
let existingSummary = '';
let existingSummaryRecordId = '';
if (summaryItems && summaryItems.length > 0) {
  const f = summaryItems[0].json.fields || summaryItems[0].json;
  existingSummary = f.Details || '';
  existingSummaryRecordId = summaryItems[0].json.id || '';
}

// Get recent history for summary generation
const historyItems = $('Get Recent History').all();
let recentConversations = '';
if (historyItems && historyItems.length > 0) {
  const msgs = historyItems
    .map(i => {
      const f = i.json.fields || i.json;
      if (!f.Message) return null;
      const role = f.Role === 'assistant' ? 'Tutor' : 'Aluna';
      return `${role}: ${f.Message.substring(0, 500)}`;
    })
    .filter(Boolean)
    .reverse();
  recentConversations = msgs.join('\n');
}

// Add the current Q&A
recentConversations += `\nAluna: ${lastQuestion}\nTutor: ${lastResponse.substring(0, 500)}`;

return [{ json: { 
  shouldUpdateSummary, 
  studentName, 
  chatId, 
  existingSummary, 
  existingSummaryRecordId,
  recentConversations,
  messageCount
} }];

const studentName = $json.studentName;
const existingSummary = $json.existingSummary;
const recentConversations = $json.recentConversations;

const prompt = `Es um assistente que gera resumos de conversas de tutoria. Atualiza o resumo cumulativo desta aluna.

ALUNA: ${studentName}

RESUMO ANTERIOR:
${existingSummary || '(primeira vez — nao ha resumo anterior)'}

CONVERSAS RECENTES:
${recentConversations.substring(0, 6000)}

Gera um resumo atualizado que inclua:
1. Disciplinas/materias que a aluna estuda (com topicos especificos)
2. Pontos fortes detectados
3. Dificuldades recorrentes
4. Estilo de aprendizagem preferido (exemplos, visual, passo-a-passo, etc)
5. Topicos ja cobertos (para nao repetir explicacoes basicas)
6. Contexto pessoal relevante mencionado nas conversas

RETORNA APENAS o resumo atualizado, sem prefacio. Maximo 500 palavras.`;

const body = {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 1024,
  messages: [{ role: 'user', content: prompt }]
};

return [{ json: { 
  body: JSON.stringify(body),
  studentName: $json.studentName,
  existingSummaryRecordId: $json.existingSummaryRecordId
} }];

const haikuResponse = $input.first().json;
let newSummary = '';
try {
  newSummary = haikuResponse.content[0].text || '';
} catch(e) {
  newSummary = 'Erro ao gerar resumo';
}

const studentName = $('Prepare Summary Body').first().json.studentName;
const existingRecordId = $('Prepare Summary Body').first().json.existingSummaryRecordId;

return [{ json: { newSummary, studentName, existingRecordId } }];
